ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  UseCodeValues: true,
  IgnoreDisabled: true,
  Transactions: payload map (item) -> {
    Status: "New",
    DataElements: [
      {
        Name: "TABPAGE_1.tp_1_dw_1",
        Type: "Form",
        Keys: ["po_no"],
        Rows: [
          {
            Edits: [
              {
                Name: "po_no",
                Value: item.payload.poNumber default ""
              },
              {
                Name: "vendor_id",
                Value: item.payload.partnerId default ""
              },
              {
                Name: "ufc_po_hdr_ud_edi_po_status",
                Value: 
                  if ((item.payload.status default "") == "SUCCESS") 
                    "Transmitted"
                  else 
                    "Failed"
              }
            ]
          }
        ]
      }
    ]
  }
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
entriesOf(
  payload
    filter ($.payload.status == "FAILED")
    groupBy ($.payload.partnerId)
)
map (entry) -> {
  partnerId: entry.key,
  errors: entry.value map (item) -> {
    poNo: item.payload.poNumber,
    "Error Details": (
      item.payload.error 
        scan /\$\.B2BMessage\.Header\.partyInformation\[1\]\.(\w+): null found, string expected/
    ) map ($[1] ++ " is null")
  }
}

